--
-- Table structure for table `user_accounts`
--

DROP TABLE IF EXISTS `user_accounts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_accounts` (
  `id` int NOT NULL AUTO_INCREMENT,
  `person_id` int NOT NULL,
  `username` varchar(64) NOT NULL,
  `password_hash` varchar(128) NOT NULL,
  `account_type` enum('EMPLOYEE','RESIDENT') NOT NULL,
  `account_role` enum('SUPER_ADMIN','ADMIN','ENGINEER','ACCOUNTANT','RESIDENT') NOT NULL,
  `status` enum('ACTIVE','DISABLED','INACTIVE') NOT NULL DEFAULT 'ACTIVE',
  `source_user_id` int DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_accounts_username` (`username`),
  UNIQUE KEY `uk_user_accounts_source_user_id` (`source_user_id`),
  KEY `idx_user_accounts_person_id` (`person_id`),
  CONSTRAINT `fk_user_accounts_person` FOREIGN KEY (`person_id`) REFERENCES `persons` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_user_accounts_source_user` FOREIGN KEY (`source_user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `chk_user_accounts_role_scope` CHECK ((((`account_type` = _utf8mb4'RESIDENT') and (`account_role` = _utf8mb4'RESIDENT')) or ((`account_type` = _utf8mb4'EMPLOYEE') and (`account_role` in (_utf8mb4'SUPER_ADMIN',_utf8mb4'ADMIN',_utf8mb4'ENGINEER',_utf8mb4'ACCOUNTANT')))))
) ENGINE=InnoDB AUTO_INCREMENT=259 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `user_accounts`
--

LOCK TABLES `user_accounts` WRITE;
/*!40000 ALTER TABLE `user_accounts` DISABLE KEYS */;
